import { Component, Input } from '@angular/core';
import { Product } from '../Model';
import { ProductService } from '../product.service';

@Component({
  selector: 'product-details',
  templateUrl: './product-details.component.html',
  styleUrls: ['./product-details.component.css']
})
export class ProductDetailsComponent {
  // dışarıdan gelen Product bilgisini almak için @Input decoratörünü kullanmamız gerekiyor
  @Input() product: Product | null;

  constructor(private productService: ProductService){
    this.product = null;
  }

  addProduct(id: number, name: string, price: string, isactive:boolean)
  {
    const p = new Product(id,name,Number.parseInt(price),isactive);
    this.productService.saveProduct(p);
    this.product = null;
  }
}
<div *ngIf="product" class="mt-3">

  <input #id class="hidden" name="id" [value]="product.id">

  <!-- eğer bize gerçekten gelen bir product bilgisi varsa bu işlemleri yapmak ngIf kullandık(Product bilgisinin gelmeme ihtimalide var) -->
  <div class="form-group">
    <label for="name">name</label>
    <input [value]="product.name" #name type="text" class="form-control" name="name">
    <!-- burada verdiğimiz #name sayesinde girilen input değerine istediğimiz yerden ulaşabiliriz -->
  </div>
  <div class="form-group">
    <label for="price">price</label>
    <input [value]="product.price" #price type="text" class="form-control" name="price">
  </div>
  <div class="form-group">
    <div class="custom-control custom-checkbox">
      <input [checked]="product.isActive" #isactive type="checkbox" class="custom-control-input" id="isActive">
      <label for="" class="custom-control-label" for="isActive"></label>
    </div>
  </div>
  <button class="btn btn-primary" (click)="addProduct(id.value,name.value,price.value,isactive.checked); name.value=''; price.value=''; isactive.checked=false;">Save Product</button>
  <!-- (click)="addProduct(name.value,price.value,isactive.checked); name.value=''; price.value=''; isactive.checked=false;" -->
</div>
